var e=[{id:`L3_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`움직이지 마세요. 릴리. 더 이상은 무리입니다.`,JPN:`動かないでください、リリー。これ以上は無理です。`,ENG:`Don't move, Lily. You mustn't push yourself any harder.`,TWN:`不要動，莉莉。你輸了。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`이...... 더러운 배신자......!`,JPN:`この……汚らわしい裏切り者……！`,ENG:`You... filthy traitor!`,TWN:`你這個……骯髒的叛徒……！`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`그 몸은 분명 마스터께서 주신 선물일 텐데......`,JPN:`その身体はマスターから授かった贈り物なのに……`,ENG:`That body must be a gift to you from the Master...`,TWN:`你的身體是主人賜予的禮物……`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`그런 걸 자기 좋을 대로 쓰다니......! 부끄럽지도 않나요?`,JPN:`それを勝手に使うなんて……！　この恥知らずめ！`,ENG:`How could you use it as you please? Don't you have any shame?`,TWN:`怎麼可以如此亂用……！難道你不覺得羞愧嗎？`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`이 몸은 선물이 아니에요.`,JPN:`この身体は贈り物ではありません。`,ENG:`This body is not a gift.`,TWN:`這個身體不是禮物。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`아픔도 다른 무엇도 못 느끼고, 마스터의 뜻대로 쓰고 버리는 도구에 불과하죠.`,JPN:`痛みも何も感じることができない、マスターの意思によって使われ、捨てられる道具にすぎません。`,ENG:`It's merely an expendable tool for the Master, unable to feel pain, or anything else for that matter.`,TWN:`是一個不能感受到疼痛和其他一切，按照主人的意願隨時可以拋棄的棋子罷了。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`그래서......`,JPN:`だから……`,ENG:`So...`,TWN:`所以……`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`그래서 그게 뭐 어쨌다는 거야?`,JPN:`だからそれがどうしたというの？`,ENG:`So what?`,TWN:`所以呢？那又怎樣？`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`당신이 나한테 가르쳤어. 우리는 마스터가 정원에 기르는 꽃이라고.`,JPN:`あなたは私に教えてくれた。私たちはマスターが庭園で育てる花だと。`,ENG:`You were the one who taught me that we are the flowers in the Master's garden.`,TWN:`是你告訴我，說我們是主人庭院裡的花朵。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`주인이 바라는 대로 아름답게 자라서, 주인만을 바라보면 된다고......!`,JPN:`主の望みどおり美しく育ち、主だけに忠誠を誓えばいいと……！`,ENG:`That all we need to do is grow beautifully and look to our Master!`,TWN:`長成主人所喜歡的模樣，盡心侍奉主人就好……！`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`그런 당신이 이제 와서 그딴 식으로 마스터를 비난할 수 있어?!`,JPN:`なのに今更そんな風にマスターを非難するなんて！`,ENG:`How can you now condemn the Master like that?`,TWN:`你覺得這樣的你，現在有資格指責主人嗎？！`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`당신에게 올바른 세상에 대해 가르쳐 주지 못한 건 미안하게 생각해요.`,JPN:`あなたに正しい生き方を教えられなかったことについては申し訳なく思います。`,ENG:`I'm sorry that I never taught you how the real world works.`,TWN:`我很抱歉我沒能教你正確的世界觀。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`당신이 눈앞에서 다른 메이드들에게 부모님이 살해당할 때 막지 못한 것도.`,JPN:`あなたの目の前であなたの両親が他のメイドたちに殺された時に止められなかったことも。`,ENG:`And I'm sorry that I failed to stop the other maids from murdering your parents right in front of you.`,TWN:`還有其他女僕當著你的面殺害你父母的時候，我也沒能及時阻止。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`하지만 릴리, 기억을 잃었을 때도 저는 당신을 지키려 했다는 사실만은 잊지 않았어요.`,JPN:`しかしリリー、記憶を失った時も私はあなたを守ろうとした事実だけは忘れていませんでした。`,ENG:`But Lily... Even when I lost my memories, I still remembered that I had tried to protect you.`,TWN:`但是莉莉，即使我失去了記憶，卻從來沒有忘記要守護你。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`제게...... 당신은 그만큼 소중한 존재였습니다.`,JPN:`私にとって……あなたはそれぐらい大切な存在でした。`,ENG:`You were that precious to me.`,TWN:`對我來說……你是很重要的。`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`LEADER_MAID_NULL_NULL`,text:{KOREA:`그러니 뒤늦게라도......`,JPN:`だから遅くなったとしても……`,ENG:`That's why I tried to protect you even when it was too late...`,TWN:`所以，雖然為時已晚……`},stage:{bg:`SS_MAID_02`,slots:{L:null,C:null,R:null}}}];export{e as default};